    async def create_trade(self, sender: Player, receiver: Player,
                           sender_items: list, receiver_items: list) -> Optional[TradeOffer]:
        async with self._lock:
            if sender.active_trade_id is not None:
                return None
            if receiver.active_trade_id is not None:
                return None

            trade_id = str(uuid.uuid4())
            trade = TradeOffer(
                trade_id=trade_id,
                sender_id=sender.player_id,
                receiver_id=receiver.player_id,
                sender_items=sender_items,
                receiver_items=receiver_items,
            )

            # Validate sender owns all offered items
            for item_id in sender_items:
                if item_id not in sender.inventory:
                    return None
                if not sender.inventory[item_id].tradeable:
                    return None

            # Validate receiver owns all offered items
            for item_id in receiver_items:
                if item_id not in receiver.inventory:
                    return None
                if not receiver.inventory[item_id].tradeable:
                    return None

            self.trades[trade_id] = trade
            sender.active_trade_id = trade_id
            receiver.active_trade_id = trade_id

            logger.info(
                f"Trade {trade_id} created between {sender.username} and {receiver.username}"
            )
            return trade

